async (page) => {
  const click = (x, y) => page.evaluate(({x, y}) => {
    document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true, ctrlKey: false }));
  }, {x, y});

  // Get current position and Forester location
  const state = await page.evaluate(() => {
    const gs = window.__latestGameState;
    const f = gs.nearby_entities.find(e => e.name === 'Forester');
    return {pos: gs.player_position, forester: f};
  });

  console.log('State:', JSON.stringify(state));

  // Navigate to Forester
  if (state.forester) {
    const f = state.forester;
    if (f.distance > 1) {
      if (f.on_screen && f.click_x) {
        await click(f.click_x, f.click_y);
        await page.waitForTimeout(3000);
      } else {
        // Walk toward Forester at (216, 114)
        const pos = state.pos;
        const dx = 216 - pos.x;
        const dy = 114 - pos.y;
        const cx = dx > 0 ? Math.min(1100, 640 + 100) : Math.max(180, 640 - 100);
        const cy = dy > 0 ? Math.min(650, 360 + 100) : Math.max(80, 360 - 100);
        await click(cx, cy);
        await page.waitForTimeout(3000);
      }
    }
  }

  const newState = await page.evaluate(() => {
    const gs = window.__latestGameState;
    const f = gs.nearby_entities.find(e => e.name === 'Forester');
    return {pos: gs.player_position, forester: f};
  });

  await page.screenshot({ path: '/tmp/kaetram_agent_2/state/screenshot.png', type: 'png' });
  return JSON.stringify(newState);
}

