async (page) => {
  // Dispatch keyboard events directly to the document/window
  const pressDown = () => page.evaluate(() => {
    const event = new KeyboardEvent('keydown', { key: 'ArrowDown', code: 'ArrowDown', keyCode: 40, bubbles: true, cancelable: true });
    document.dispatchEvent(event);
    window.dispatchEvent(event);
    document.getElementById('canvas').dispatchEvent(event);
  });
  const releaseDown = () => page.evaluate(() => {
    const event = new KeyboardEvent('keyup', { key: 'ArrowDown', code: 'ArrowDown', keyCode: 40, bubbles: true, cancelable: true });
    document.dispatchEvent(event);
    window.dispatchEvent(event);
    document.getElementById('canvas').dispatchEvent(event);
  });

  // Rapid press 30 times south
  for (let i = 0; i < 30; i++) {
    await pressDown();
    await page.waitForTimeout(300);
    await releaseDown();
    await page.waitForTimeout(100);
  }

  await page.screenshot({ path: '/tmp/kaetram_agent_2/state/screenshot.png', type: 'png' });
  const pos = await page.evaluate(() => JSON.stringify({x: window.game.player.gridX, y: window.game.player.gridY}));
  return pos;
}

async (page) => {
