async (page) => {
  // Check game.map.objects for chests, hammer, special objects
  const mapObjects = await page.evaluate(() => {
    const map = window.game.map;
    const objects = map?.objects;

    // Get objects near south coast area
    const nearbyObjs = [];
    if (Array.isArray(objects)) {
      for (const obj of objects) {
        if (obj.y > 190 && obj.y < 250 && obj.x > 100 && obj.x < 250) {
          nearbyObjs.push(obj);
        }
      }
    } else if (objects) {
      return JSON.stringify({objectsType: typeof objects, keys: Object.keys(objects).slice(0,10)});
    }

    // Also look at game entities store
    const entityStore = window.game.entities?.entities;
    const entityKeys = entityStore ? Object.keys(entityStore).slice(0, 10) : [];

    return JSON.stringify({
      objectCount: Array.isArray(objects) ? objects.length : 'not array',
      nearbyObjs: nearbyObjs.slice(0, 20),
      entityKeys
    });
  });
  return mapObjects;
}

