async (page) => {
  const result = await page.evaluate(() => {
    const map = window.game.map;
    const px = window.game.player.gridX;
    const py = window.game.player.gridY;

    // Check map.objects (special interactive objects)
    let objInfo = 'none';
    if (map.objects) {
      const objType = typeof map.objects;
      if (Array.isArray(map.objects)) {
        objInfo = { isArray: true, length: map.objects.length, sample: JSON.stringify(map.objects.slice(0, 10)) };
      } else if (objType === 'object') {
        const keys = Object.keys(map.objects);
        objInfo = { isObj: true, keyCount: keys.length, sampleKeys: keys.slice(0, 20) };
        // Check near player
        const nearby = {};
        for (const k of keys) {
          // key might be "x,y" format or just an id
          nearby[k] = map.objects[k];
        }
        // Show first 20
        objInfo.sample = Object.fromEntries(Object.entries(nearby).slice(0, 20));
      }
    }

    // Check tileSize
    const tileSize = map.tileSize;

    // Try to find the actual game area/zone handling
    let inputKeys = Object.keys(window.game.input || {}).filter(k => typeof window.game.input[k] !== 'function').slice(0, 20);

    return { objInfo, tileSize, inputKeys, px, py };
  });
  return JSON.stringify(result).slice(0, 3000);
}

